/**
 * Generate src/generated/shadowPlacements.ts from the authored-shadow manifests
 * (T3.29). This is the ONLY place runtime placement values come from, so the
 * JSON manifests and the TypeScript can never drift. Run via `npm run shadow:gen`
 * (also run automatically by `npm run pack:atlas`).
 *
 * Usage: node tools/gen-shadow-placements.mjs [--check]
 *   --check : exit non-zero if the generated file is stale (for CI / tests).
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import process from 'node:process';
import { fileURLToPath } from 'node:url';

import { labRecord, listBuildings, placementRecord, readManifest } from './shadow-lib.mjs';

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), '..');
const genDir = join(repoRoot, 'src', 'generated');
const placementsPath = join(genDir, 'shadowPlacements.ts');
const labPath = join(genDir, 'shadowLab.ts');

function manifests() {
  return listBuildings(repoRoot).map((b) =>
    readManifest(join(repoRoot, 'tools', 'shadow-overrides', `${b}_shadow.json`)),
  );
}

function renderPlacements(ms) {
  const entries = ms.map((m) => {
    const p = placementRecord(m);
    return `  ${JSON.stringify(m.frame)}: { logicalWidth: ${p.logicalWidth}, logicalHeight: ${p.logicalHeight}, anchorX: ${p.anchorX}, anchorY: ${p.anchorY}, tuckRatio: ${p.tuckRatio} },`;
  });
  return `// AUTO-GENERATED by tools/gen-shadow-placements.mjs from tools/shadow-overrides/*.json.
// Do NOT edit by hand - run \`npm run shadow:gen\` to regenerate.
//
// Authored building-shadow runtime placement (T3.29). Each entry's anchor is the
// building's ground point in logical-canvas pixels, DERIVED in the manifest as
// sourceFrameRect + sourceGroundPoint. The manifest is the source of truth; this
// file exists only so the runtime does not parse JSON at boot.

export interface ShadowPlacementOverride {
  logicalWidth: number;
  logicalHeight: number;
  anchorX: number;
  anchorY: number;
  tuckRatio: number;
}

export const SHADOW_PLACEMENT_OVERRIDES: Readonly<Record<string, ShadowPlacementOverride>> = {
${entries.join('\n')}
};
`;
}

function renderLab(ms) {
  const entries = ms.map((m) => {
    const l = labRecord(m);
    return `  ${JSON.stringify(l.building)}: ${JSON.stringify(l)},`;
  });
  return `// AUTO-GENERATED by tools/gen-shadow-placements.mjs from tools/shadow-overrides/*.json.
// Do NOT edit by hand - run \`npm run shadow:gen\` to regenerate.
//
// Dev-only preview data for ShadowLabScene (T3.29). NOT used by the shipped game
// loop - only the dev shadow-lab route reads it. Holds the source frame, variant
// frames, ground point, derived anchor, and a preview scale per authored shadow.

export interface ShadowLabEntry {
  building: string;
  frame: string;
  sourceFrame: string;
  variants: string[];
  logicalWidth: number;
  logicalHeight: number;
  sourceFrameWidth: number;
  sourceFrameHeight: number;
  groundPointX: number;
  groundPointY: number;
  anchorX: number;
  anchorY: number;
  tuckRatio: number;
  previewScale: number;
}

export const SHADOW_LAB_ENTRIES: Readonly<Record<string, ShadowLabEntry>> = {
${entries.join('\n')}
};
`;
}

const check = process.argv.includes('--check');
const ms = manifests();
const outputs = [
  { path: placementsPath, text: renderPlacements(ms) },
  { path: labPath, text: renderLab(ms) },
];

if (check) {
  let stale = false;
  for (const o of outputs) {
    const current = existsSync(o.path) ? readFileSync(o.path, 'utf8') : null;
    if (current !== o.text) {
      console.error(`shadow:gen --check FAILED: ${o.path} is stale. Run \`npm run shadow:gen\`.`);
      stale = true;
    }
  }
  if (stale) process.exit(1);
  console.log('shadow:gen --check OK: generated files match the manifests.');
} else {
  mkdirSync(genDir, { recursive: true });
  for (const o of outputs) writeFileSync(o.path, o.text);
  console.log(`wrote generated placements + lab manifest (${ms.length} authored shadow(s))`);
}
